private class SessionStore(context: Context) {
    private val prefs: SharedPreferences =
        context.getSharedPreferences(SocialLoginConfig.PREFS_NAME, Context.MODE_PRIVATE)

    fun saveToken(provider: Provider, token: String) {
        prefs.edit().putString(key(provider), token).apply()
    }

    fun getToken(provider: Provider): String? = prefs.getString(key(provider), null)

    fun clear(provider: Provider) {
        prefs.edit().remove(key(provider)).apply()
    }

    private fun key(provider: Provider): String =
        when (provider) {
            Provider.FACEBOOK -> SocialLoginConfig.KEY_FACEBOOK_TOKEN
            Provider.GOOGLE -> SocialLoginConfig.KEY_GOOGLE_TOKEN
        }
}

private class OAuthState(private val state: String = UUID.randomUUID().toString()) {
    fun value(): String = state
    fun matches(other: String?): Boolean = state == other
}

private data class OAuthResponse(
    val code: String?,
    val state: String?,
    val error: String?,
    val errorDescription: String?
)

private fun parseQuery(uri: Uri): Map<String, String?> {
    val result = mutableMapOf<String, String?>()
    for (name in uri.queryParameterNames) {
        result[name] = uri.getQueryParameter(name)
    }
    return result
}

private fun Uri.extractOAuthResponse(): OAuthResponse {
    val query = parseQuery(this)
    return OAuthResponse(
        code = query["code"],
        state = query["state"],
        error = query["error"],
        errorDescription = query["error_description"]
    )
}

private class BrowserOAuthLauncher(
    private val context: Context,
    private val redirectUri: String,
    private val authUrlBuilder: (String) -> String
) {
    @MainThread
    suspend fun start(): OAuthResponse {
        val state = OAuthState()
        val result = CompletableDeferred<OAuthResponse>()
        val deepLinkReceiver = OAuthDeepLinkReceiver.install(context, redirectUri.toUri()) { uri ->
            if (!result.isCompleted) {
                result.complete(uri.extractOAuthResponse())
            }
        }

        val url = authUrlBuilder(state.value())
        val customTabsIntent = CustomTabsIntent.Builder().build()
        customTabsIntent.launchUrl(context, url.toUri())

        val response = withContext(Dispatchers.Main) {
            result.await()
        }
        deepLinkReceiver.close()
        return response
    }
}

private class OAuthDeepLinkReceiver private constructor(
    private val context: Context,
    private val callback: (Uri) -> Unit
) : DefaultLifecycleObserver {

    companion object {
        fun install(context: Context, expectedRedirectUri: Uri, callback: (Uri) -> Unit): OAuthDeepLinkReceiver {
            val receiver = OAuthDeepLinkReceiver(context.applicationContext, callback)
            ProcessLifecycleOwner.get().lifecycle.addObserver(receiver)
            return receiver
        }
    }

    fun close() {
        ProcessLifecycleOwner.get().lifecycle.removeObserver(this)
    }

    override fun onStart(owner: LifecycleOwner) {
        super.onStart(owner)
    }

    fun handle(uri: Uri) {
        callback(uri)
    }
}

class FacebookLoginClient(private val context: Context) : SocialLoginClient {
    private val store = SessionStore(context)

    override suspend fun login(activity: Activity): SocialLoginResult {
        return try {
            val authUrl = buildFacebookAuthUrl()
            val redirect = performBrowserLogin(activity, authUrl)
            if (redirect.error != null) return SocialLoginResult.Failure(IllegalStateException(redirect.errorDescription ?: redirect.error))
            val code = redirect.code ?: return SocialLoginResult.Failure(IllegalStateException("Missing authorization code"))
            val token = exchangeCodeForToken(code)
            store.saveToken(Provider.FACEBOOK, token.accessToken)
            val user = fetchUser(token.accessToken)
            SocialLoginResult.Success(user.copy(accessToken = token.accessToken))
        } catch (e: Throwable) {
            SocialLoginResult.Failure(e)
        }
    }

    override suspend fun logout(context: Context) {
        store.clear(Provider.FACEBOOK)
    }

    private fun buildFacebookAuthUrl(): String {
        val state = UUID.randomUUID().toString()
        return Uri.parse(SocialLoginConfig.FACEBOOK_AUTH_ENDPOINT).buildUpon()
            .appendQueryParameter("client_id", SocialLoginConfig.FACEBOOK_APP_ID)
            .appendQueryParameter("redirect_uri", SocialLoginConfig.REDIRECT_URI)
            .appendQueryParameter("response_type", "code")
            .appendQueryParameter("scope", "public_profile,email")
            .appendQueryParameter("state", state)
            .build()
            .toString()
    }

    private suspend fun performBrowserLogin(activity: Activity, authUrl: String): OAuthResponse {
        val launcher = BrowserOAuthLauncher(activity, SocialLoginConfig.REDIRECT_URI) { _ -> authUrl }
        return launcher.start()
    }

    private suspend fun exchangeCodeForToken(code: String): FacebookTokenResponse = withContext(Dispatchers.IO) {
        val url = URL(
            Uri.parse(SocialLoginConfig.FACEBOOK_TOKEN_ENDPOINT).buildUpon()
                .appendQueryParameter("client_id", SocialLoginConfig.FACEBOOK_APP_ID)
                .appendQueryParameter("client_secret", SocialLoginConfig.FACEBOOK_APP_SECRET)
                .appendQueryParameter("redirect_uri", SocialLoginConfig.REDIRECT_URI)
                .appendQueryParameter("code", code)
                .build()
                .toString()
        )
        val conn = url.openConnection() as HttpURLConnection
        conn.requestMethod = "GET"
        conn.connectTimeout = 15000
        conn.readTimeout = 15000
        conn.inputStream.bufferedReader().use { reader ->
            val json = JSONObject(reader.readText())
            FacebookTokenResponse(
                accessToken = json.getString("access_token"),
                tokenType = json.optString("token_type", "bearer"),
                expiresIn = json.optLong("expires_in", 0L)
            )
        }
    }

    private suspend fun fetchUser(accessToken: String): SocialUser = withContext(Dispatchers.IO) {
        val uri = Uri.parse(SocialLoginConfig.FACEBOOK_ME_ENDPOINT).buildUpon()
            .appendQueryParameter("fields", "id,name,email,first_name,last_name,picture")
            .appendQueryParameter("access_token", accessToken)
            .build()
        val conn = (URL(uri.toString()).openConnection() as HttpURLConnection).apply {
            requestMethod = "GET"
            connectTimeout = 15000
            readTimeout = 15000
        }
        conn.inputStream.bufferedReader().use { reader ->
            val json = JSONObject(reader.readText())
            val pictureData = json.optJSONObject("picture")
                ?.optJSONObject("data")
            SocialUser(
                provider = Provider.FACEBOOK,
                id = json.getString("id"),
                email = json.optString("email", null),
                displayName = json.optString("name", null),
                givenName = json.optString("first_name", null),
                familyName = json.optString("last_name", null),
                photoUrl = pictureData?.optString("url", null),
                accessToken = accessToken
            )
        }
    }

    private data class FacebookTokenResponse(
        val accessToken: String,
        val tokenType: String,
        val expiresIn: Long
    )
}

class GoogleLoginClient(private val context: Context) : SocialLoginClient {
    private val store = SessionStore(context)

    override suspend fun login(activity: Activity): SocialLoginResult {
        return try {
            val authUrl = buildGoogleAuthUrl()
            val redirect = performBrowserLogin(activity, authUrl)
