            val code = redirect.code ?: return SocialLoginResult.Failure(IllegalStateException("Missing authorization code"))
            val token = exchangeCodeForToken(code)
            store.saveToken(Provider.GOOGLE, token.accessToken)
            val user = fetchUser(token.accessToken, token.idToken)
            SocialLoginResult.Success(user)
        } catch (e: Throwable) {
            SocialLoginResult.Failure(e)
        }
    }

    override suspend fun logout(context: Context) {
        store.clear(Provider.GOOGLE)
    }

    private fun buildGoogleAuthUrl(): String {
        val state = UUID.randomUUID().toString()
        return Uri.parse(SocialLoginConfig.GOOGLE_AUTH_ENDPOINT).buildUpon()
            .appendQueryParameter("client_id", SocialLoginConfig.GOOGLE_CLIENT_ID)
            .appendQueryParameter("redirect_uri", SocialLoginConfig.REDIRECT_URI)
            .appendQueryParameter("response_type", "code")
            .appendQueryParameter("scope", "openid email profile")
            .appendQueryParameter("access_type", "offline")
            .appendQueryParameter("prompt", "consent")
            .appendQueryParameter("state", state)
            .build()
            .toString()
    }

    private suspend fun performBrowserLogin(activity: Activity, authUrl: String): OAuthResponse {
        val launcher = BrowserOAuthLauncher(activity, SocialLoginConfig.REDIRECT_URI) { _ -> authUrl }
        return launcher.start()
    }

    private suspend fun exchangeCodeForToken(code: String): GoogleTokenResponse = withContext(Dispatchers.IO) {
        val postData = buildString {
            append("code=").append(Uri.encode(code))
            append("&client_id=").append(Uri.encode(SocialLoginConfig.GOOGLE_CLIENT_ID))
            append("&client_secret=").append(Uri.encode(SocialLoginConfig.GOOGLE_CLIENT_SECRET))
            append("&redirect_uri=").append(Uri.encode(SocialLoginConfig.REDIRECT_URI))
            append("&grant_type=").append(Uri.encode("authorization_code"))
        }
        val conn = (URL(SocialLoginConfig.GOOGLE_TOKEN_ENDPOINT).openConnection() as HttpURLConnection).apply {
            requestMethod = "POST"
            doOutput = true
            connectTimeout = 15000
            readTimeout = 15000
            setRequestProperty("Content-Type", "application/x-www-form-urlencoded")
        }
        conn.outputStream.use { it.write(postData.toByteArray()) }
        conn.inputStream.bufferedReader().use { reader ->
            val json = JSONObject(reader.readText())
            GoogleTokenResponse(
                accessToken = json.getString("access_token"),
                idToken = json.optString("id_token", null),
                tokenType = json.optString("token_type", "Bearer"),
                expiresIn = json.optLong("expires_in", 0L)
            )
        }
    }

    private suspend fun fetchUser(accessToken: String, idToken: String?): SocialUser = withContext(Dispatchers.IO) {
        val conn = (URL(SocialLoginConfig.GOOGLE_USERINFO_ENDPOINT).openConnection() as HttpURLConnection).apply {
            requestMethod = "GET"
            connectTimeout = 15000
            readTimeout = 15000
            setRequestProperty("Authorization", "Bearer $accessToken")
        }
        conn.inputStream.bufferedReader().use { reader ->
            val json = JSONObject(reader.readText())
            SocialUser(
                provider = Provider.GOOGLE,
                id = json.getString("sub"),
                email = json.optString("email", null),
                displayName = json.optString("name", null),
                givenName = json.optString("given_name", null),
                familyName = json.optString("family_name", null),
                photoUrl = json.optString("picture", null),
                accessToken = accessToken,
                idToken = idToken
            )
        }
    }

    private data class GoogleTokenResponse(
        val accessToken: String,
        val idToken: String?,
        val tokenType: String,
        val expiresIn: Long
    )
}

